mapper.select:
select
    payment_number, fee_id, payment_amount, payment_date, payment_method, bank_account, transaction_number,
    payer_account, payee_account, payment_status, payment_remark, refund_amount, refund_date, refund_remark, create_time, update_time
from t_env_fee_payments p


        and p.fee_id = #{feeId}



            and exists (select 1 from t_env_fees es where es.ent_code = #{entCode} and es.fee_id = p.fee_id)



                and exists (select 1 from t_env_fees es where es.fee_id = p.fee_id and es.ent_code in

                    #{entCode}

                )




        and p.payment_date between #{paymentStart} and #{paymentEnd}


        and p.transaction_number = #{transactionNumber}


        and p.payment_status = #{paymentStatus}


order by p.payment_number desc

mapper.update:
update t_env_fee_payments
payment_amount = #{paymentAmount}, payment_date = #{paymentDate}, payment_method = #{paymentMethod}, bank_account = #{bankAccount}, transaction_number = #{transactionNumber}, payer_account = #{payerAccount}, payee_account = #{payeeAccount}, payment_status = #{paymentStatus}, payment_remark = #{paymentRemark}, refund_amount = #{refundAmount}, refund_date = now(), refund_remark = #{refundRemark},
where payment_number = #{paymentNumber}
